-- ---- Stub: FileHandle:read -----------------------------------------------
--@api-stub: FileHandle:read
-- Read a fixed-size binary record from a save file -- pass the byte
-- count to read exactly one record without over-reading.
local fh_r = lurek.filesystem.openFile("save/progress.dat", "r")
if fh_r then
    local record = fh_r:read(64)
    print("record bytes read:", #record)
    fh_r:close()
end

-- ---- Stub: FileHandle:readLine -------------------------------------------
--@api-stub: FileHandle:readLine
